#include <algorithm>
#include <atomic>
#include <cstring>
#include <thread>
#include <vector>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/sequence.h"

template <typename T, typename KeyFunc>
parlay::sequence<T> parallel_radix_sort(parlay::slice<T*, T*> input, 
                                        KeyFunc key_func, 
                                        size_t total_bits) {
    size_t n = input.size();
    if (n <= 1) return parlay::sequence<T>(input.begin(), input.end());

    // Use 8-bit radix for better cache performance
    constexpr size_t RADIX_BITS = 8;
    constexpr size_t RADIX = 1 << RADIX_BITS;
    constexpr size_t MASK = RADIX - 1;

    // Threshold for switching to sequential sort
    constexpr size_t SEQUENTIAL_THRESHOLD = 1024;

    if (n < SEQUENTIAL_THRESHOLD) {
        parlay::sequence<T> result(input.begin(), input.end());
        std::stable_sort(result.begin(), result.end(), 
                        [&](const T& a, const T& b) {
                            return key_func(a) < key_func(b);
                        });
        return result;
    }

    // Calculate number of passes needed
    size_t num_passes = (total_bits + RADIX_BITS - 1) / RADIX_BITS;

    // Create buffers for ping-pong approach
    parlay::sequence<T> buffer1(input.begin(), input.end());
    parlay::sequence<T> buffer2(n);

    T* src = buffer1.data();
    T* dst = buffer2.data();

    // Get number of threads for parallel execution
    size_t num_threads = parlay::num_workers();

    for (size_t pass = 0; pass < num_passes; ++pass) {
        size_t shift = pass * RADIX_BITS;

        // Phase 1: Local histogram computation (parallel)
        std::vector<std::vector<size_t>> local_counts(num_threads, 
                                                      std::vector<size_t>(RADIX, 0));

        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t chunk_size = (n + num_threads - 1) / num_threads;
            size_t start = tid * chunk_size;
            size_t end = std::min(start + chunk_size, n);

            auto& counts = local_counts[tid];

            // Count with prefetching
            for (size_t i = start; i < end; ++i) {
                if (i + 8 < end) {
                    __builtin_prefetch(&src[i + 8], 0, 1);
                }
                size_t key = (key_func(src[i]) >> shift) & MASK;
                counts[key]++;
            }
        });

        // Phase 2: Compute global offsets
        std::vector<size_t> global_offsets(RADIX, 0);
        std::vector<std::vector<size_t>> thread_offsets(num_threads, 
                                                        std::vector<size_t>(RADIX));

        for (size_t r = 0; r < RADIX; ++r) {
            size_t offset = 0;
            for (size_t t = 0; t < num_threads; ++t) {
                thread_offsets[t][r] = global_offsets[r] + offset;
                offset += local_counts[t][r];
            }
            global_offsets[r] += offset;
            if (r < RADIX - 1) {
                global_offsets[r + 1] = global_offsets[r];
            }
        }

        // Phase 3: Scatter elements to destination (parallel)
        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t chunk_size = (n + num_threads - 1) / num_threads;
            size_t start = tid * chunk_size;
            size_t end = std::min(start + chunk_size, n);

            // Local write positions for this thread
            std::vector<size_t> write_pos = thread_offsets[tid];

            // Process elements with write combining
            constexpr size_t BLOCK_SIZE = 64;
            for (size_t block_start = start; block_start < end; block_start += BLOCK_SIZE) {
                size_t block_end = std::min(block_start + BLOCK_SIZE, end);

                // First pass: determine destinations
                size_t keys[BLOCK_SIZE];
                size_t positions[BLOCK_SIZE];

                for (size_t i = block_start; i < block_end; ++i) {
                    size_t idx = i - block_start;
                    keys[idx] = (key_func(src[i]) >> shift) & MASK;
                    positions[idx] = write_pos[keys[idx]]++;
                }

                // Second pass: write to destination
                for (size_t i = block_start; i < block_end; ++i) {
                    size_t idx = i - block_start;
                    dst[positions[idx]] = src[i];
                }
            }
        }, 1);

        // Swap buffers for next iteration
        std::swap(src, dst);
    }

    // Return the correct buffer
    if (num_passes % 2 == 0) {
        return buffer1;
    } else {
        return buffer2;
    }
}

template <class T>
auto int_sort(parlay::slice<T*, T*> In, size_t bits) {
    auto key_func = [](T x) { return x; };
    return parallel_radix_sort(In, key_func, bits);
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E, F>*, std::pair<E, F>*> In, size_t bits) {
    auto key_func = [](std::pair<E, F> x) { return x.first; };
    return parallel_radix_sort(In, key_func, bits);
}
```
