#include <atomic>
#include <cstring>
#include <thread>
#include <vector>
#include <immintrin.h>
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/primitives.h"

namespace {
    constexpr size_t RADIX_BITS = 8;
    constexpr size_t RADIX_SIZE = 1 << RADIX_BITS;
    constexpr size_t RADIX_MASK = RADIX_SIZE - 1;
    constexpr size_t CACHE_LINE_SIZE = 64;
    constexpr size_t SERIAL_THRESHOLD = 1024;

    // Optimized parallel counting sort for a single radix pass
    template<typename T, typename KeyFunc>
    void parallel_counting_sort(T* input, T* output, size_t n, 
                                size_t shift, KeyFunc get_key) {
        if (n < SERIAL_THRESHOLD) {
            // Serial counting sort for small inputs
            size_t counts[RADIX_SIZE] = {0};
            for (size_t i = 0; i < n; ++i) {
                counts[(get_key(input[i]) >> shift) & RADIX_MASK]++;
            }

            size_t offsets[RADIX_SIZE];
            offsets[0] = 0;
            for (size_t i = 1; i < RADIX_SIZE; ++i) {
                offsets[i] = offsets[i-1] + counts[i-1];
            }

            for (size_t i = 0; i < n; ++i) {
                size_t bucket = (get_key(input[i]) >> shift) & RADIX_MASK;
                output[offsets[bucket]++] = input[i];
            }
            return;
        }

        size_t num_threads = parlay::num_workers();
        size_t block_size = (n + num_threads - 1) / num_threads;

        // Thread-local histograms with cache line padding
        struct alignas(CACHE_LINE_SIZE) LocalHist {
            size_t counts[RADIX_SIZE];
            LocalHist() { std::memset(counts, 0, sizeof(counts)); }
        };

        std::vector<LocalHist> local_counts(num_threads);

        // Parallel histogram computation
        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t start = tid * block_size;
            size_t end = std::min(start + block_size, n);
            auto& local = local_counts[tid].counts;

            // Unroll loop for better performance
            size_t i = start;
            for (; i + 3 < end; i += 4) {
                local[(get_key(input[i]) >> shift) & RADIX_MASK]++;
                local[(get_key(input[i+1]) >> shift) & RADIX_MASK]++;
                local[(get_key(input[i+2]) >> shift) & RADIX_MASK]++;
                local[(get_key(input[i+3]) >> shift) & RADIX_MASK]++;
            }
            for (; i < end; ++i) {
                local[(get_key(input[i]) >> shift) & RADIX_MASK]++;
            }
        });

        // Compute global offsets
        size_t global_offsets[RADIX_SIZE] = {0};
        for (size_t r = 0; r < RADIX_SIZE; ++r) {
            for (size_t t = 0; t < num_threads; ++t) {
                size_t temp = local_counts[t].counts[r];
                local_counts[t].counts[r] = global_offsets[r];
                global_offsets[r] += temp;
            }
        }

        // Parallel scatter with local buffers to reduce contention
        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t start = tid * block_size;
            size_t end = std::min(start + block_size, n);

            // Use local buffer for each radix to reduce random writes
            std::vector<std::vector<T>> local_buffers(RADIX_SIZE);
            constexpr size_t BUFFER_SIZE = 32;

            for (size_t i = start; i < end; ++i) {
                size_t bucket = (get_key(input[i]) >> shift) & RADIX_MASK;
                local_buffers[bucket].push_back(input[i]);

                if (local_buffers[bucket].size() >= BUFFER_SIZE) {
                    size_t offset = local_counts[tid].counts[bucket];
                    std::memcpy(&output[offset], local_buffers[bucket].data(), 
                               local_buffers[bucket].size() * sizeof(T));
                    local_counts[tid].counts[bucket] += local_buffers[bucket].size();
                    local_buffers[bucket].clear();
                }
            }

            // Flush remaining elements
            for (size_t r = 0; r < RADIX_SIZE; ++r) {
                if (!local_buffers[r].empty()) {
                    size_t offset = local_counts[tid].counts[r];
                    std::memcpy(&output[offset], local_buffers[r].data(), 
                               local_buffers[r].size() * sizeof(T));
                }
            }
        });
    }

    template<typename T, typename KeyFunc>
    parlay::sequence<T> optimized_radix_sort(parlay::slice<T*, T*> input, 
                                             KeyFunc get_key, size_t bits) {
        size_t n = input.size();
        if (n <= 1) return parlay::to_sequence(input);

        // For very small inputs, use serial sort
        if (n < SERIAL_THRESHOLD) {
            auto result = parlay::to_sequence(input);
            std::stable_sort(result.begin(), result.end(), 
                           [&](const T& a, const T& b) {
                               return get_key(a) < get_key(b);
                           });
            return result;
        }

        parlay::sequence<T> buffer1 = parlay::to_sequence(input);
        parlay::sequence<T> buffer2(n);

        T* current = buffer1.data();
        T* next = buffer2.data();

        // Process radix passes
        size_t num_passes = (bits + RADIX_BITS - 1) / RADIX_BITS;
        for (size_t pass = 0; pass < num_passes; ++pass) {
            size_t shift = pass * RADIX_BITS;

            // Skip unnecessary passes for high bits
            if (shift >= bits) break;

            parallel_counting_sort(current, next, n, shift, get_key);
            std::swap(current, next);
        }

        // Return the correct buffer
        if (current == buffer1.data()) {
            return buffer1;
        } else {
            return buffer2;
        }
    }
}

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
    auto f = [](T x) { return x; };
    return optimized_radix_sort(In, f, bits);
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
    auto f = [](std::pair<E,F> x) { return x.first; };
    return optimized_radix_sort(In, f, bits);
}
```
