  auto keys = parlay::delayed_seq<size_t>(In.size(), get_key);
  return parlay::log2_up(parlay::reduce(keys, parlay::maxm<size_t>()));
}

// Parallel radix sort implementation
template <typename T, typename F>
void parallel_radix_sort_r(parlay::slice<T*, T*> In, 
                          parlay::slice<T*, T*> Out,
                          F get_key,
                          size_t bits_done, 
                          size_t bits_remaining) {

  size_t n = In.size();

  // Base case: use serial sort for small inputs
  constexpr size_t SERIAL_THRESHOLD = 8192;
  if (n < SERIAL_THRESHOLD) {
    parlay::internal::seq_radix_sort<std::true_type, parlay::uninitialized_relocate_tag>
      (In, Out, In, get_key, bits_done + bits_remaining);
    return;
  }

  // Choose radix - use 8 bits for good cache performance
  constexpr size_t RADIX_BITS = 8;
  size_t bits_to_sort = std::min(RADIX_BITS, bits_remaining);
  size_t num_buckets = 1 << bits_to_sort;
  size_t mask = num_buckets - 1;

  // Parallel histogram computation with local counts to reduce contention
  size_t num_blocks = std::min<size_t>(n / 1024 + 1, parlay::num_workers() * 8);
  size_t block_size = (n + num_blocks - 1) / num_blocks;

  auto counts = parlay::sequence<parlay::sequence<size_t>>(num_blocks);

  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = i * block_size;
    size_t end = std::min(start + block_size, n);
    counts[i] = parlay::sequence<size_t>(num_buckets, 0);

    for (size_t j = start; j < end; j++) {
      size_t key = get_key(In[j]);
      size_t bucket = (key >> bits_done) & mask;
      counts[i][bucket]++;
    }
  });

  // Compute global offsets
  auto global_counts = parlay::sequence<size_t>(num_buckets, 0);
  for (size_t b = 0; b < num_buckets; b++) {
    for (size_t i = 0; i < num_blocks; i++) {
      global_counts[b] += counts[i][b];
    }
  }

  auto offsets = parlay::scan(global_counts).first;

  // Compute per-block offsets
  auto block_offsets = parlay::sequence<parlay::sequence<size_t>>(num_blocks);
  for (size_t i = 0; i < num_blocks; i++) {
    block_offsets[i] = parlay::sequence<size_t>(num_buckets);
    for (size_t b = 0; b < num_buckets; b++) {
      block_offsets[i][b] = offsets[b];
      for (size_t j = 0; j < i; j++) {
        block_offsets[i][b] += counts[j][b];
      }
    }
  }

  // Parallel distribution phase
  parlay::parallel_for(0, num_blocks, [&](size_t i) {
    size_t start = i * block_size;
    size_t end = std::min(start + block_size, n);
    auto local_offsets = block_offsets[i];

    for (size_t j = start; j < end; j++) {
      size_t key = get_key(In[j]);
      size_t bucket = (key >> bits_done) & mask;
      size_t pos = local_offsets[bucket]++;
      Out[pos] = std::move(In[j]);
    }
  });

  // Recursively sort each bucket if more bits remain
  if (bits_remaining > bits_to_sort) {
    parlay::parallel_for(0, num_buckets, [&](size_t i) {
      size_t start = offsets[i];
      size_t len = global_counts[i];
      if (len > 0) {
        auto bucket_in = Out.cut(start, start + len);
        auto bucket_out = In.cut(start, start + len);
        parallel_radix_sort_r(bucket_in, bucket_out, get_key, 
                            bits_done + bits_to_sort, 
                            bits_remaining - bits_to_sort);
        // Copy back if necessary
        if ((bits_remaining - bits_to_sort) % (2 * RADIX_BITS) != 0) {
          parlay::parallel_for(0, len, [&](size_t j) {
            Out[start + j] = std::move(In[start + j]);
          });
        }
      }
    }, 1);
  }
}

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  auto Out = parlay::sequence<T>::uninitialized(In.size());
  auto f = [&] (T x) {return x;};

  if (bits == 0) bits = num_bits(In, f);

  // Use parallel sort for larger inputs
  if (In.size() > 1000) {
