#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/internal/counting_sort.h"

template <class Seq, class F>
int num_bits(Seq In, F g) {
  auto get_key = [&] (size_t i) {return g(In[i]);};
  auto keys = parlay::delayed_seq<size_t>(In.size(), get_key);
  return parlay::log2_up(parlay::reduce(keys, parlay::maxm<size_t>()));
}

// Parallel radix sort implementation
template <typename T, typename F>
void parallel_radix_sort(parlay::slice<T*, T*> In, 
                         parlay::slice<T*, T*> Out,
                         F get_key,
                         size_t bits) {
  size_t n = In.size();

  // Use serial sort for small inputs
  if (n < 1000) {
    parlay::internal::seq_radix_sort<std::true_type,parlay::uninitialized_relocate_tag>
         (In, Out, In, get_key, bits);
    return;
  }

  // Radix sort parameters
  constexpr size_t RADIX_BITS = 8;  // Process 8 bits at a time
  constexpr size_t RADIX = 1 << RADIX_BITS;
  size_t num_rounds = (bits + RADIX_BITS - 1) / RADIX_BITS;

  // Allocate temporary buffer if needed
  parlay::sequence<T> temp;
  T* source = In.begin();
  T* dest = Out.begin();

  // If odd number of rounds, we need a temporary buffer
  if (num_rounds % 2 == 1) {
    temp = parlay::sequence<T>::uninitialized(n);
    dest = temp.begin();
  }

  for (size_t round = 0; round < num_rounds; round++) {
    size_t shift = round * RADIX_BITS;
    size_t mask = RADIX - 1;

    // Extract keys for this round
    auto keys = parlay::tabulate(n, [&](size_t i) {
      return static_cast<size_t>((get_key(source[i]) >> shift) & mask);
    });

    // Count occurrences of each radix value
    auto counts = parlay::histogram_by_key(keys, RADIX);

    // Compute offsets (exclusive scan)
    auto offsets = parlay::scan(counts, parlay::addm<size_t>()).first;

    // Create position array for each element
    auto positions = parlay::sequence<size_t>::uninitialized(n);

    // Parallel counting sort
    parlay::parallel_for(0, RADIX, [&](size_t i) {
      size_t start = (i == 0) ? 0 : offsets[i-1];
      size_t end = offsets[i];
      size_t count = 0;

      for (size_t j = 0; j < n; j++) {
        if (keys[j] == i) {
          positions[j] = start + count++;
        }
      }
    }, 1);

    // Scatter elements to their new positions
    parlay::parallel_for(0, n, [&](size_t i) {
      dest[positions[i]] = std::move(source[i]);
    });

    // Swap source and dest for next round
    std::swap(source, dest);
  }

  // If we ended up in the wrong buffer, copy back
  if (source != Out.begin()) {
    parlay::parallel_for(0, n, [&](size_t i) {
      Out[i] = std::move(source[i]);
    });
  }
}

// Optimized parallel counting sort for better cache performance
template <typename T, typename F>
void parallel_counting_radix_sort(parlay::slice<T*, T*> In,
                                  parlay::slice<T*, T*> Out, 
                                  F get_key,
                                  size_t bits) {
  size_t n = In.size();

  // For small inputs, use serial sort
  if (n < 10000) {
