  auto keys = parlay::tabulate(n, [&](size_t i) { return get_key(In[i]); });
  auto sorted_indices = parlay::internal::integer_sort_with_indices(keys, bits);

  // Permute based on sorted indices
  parlay::parallel_for(0, n, [&](size_t i) {
    Out[i] = In[sorted_indices[i]];
  });
}

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  auto Out = parlay::sequence<T>::uninitialized(In.size());
