```cpp
#include "parlay/primitives.h"
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/internal/counting_sort.h"

template <class Seq, class F>
int num_bits(Seq In, F g) {
  auto get_key = [&] (size_t i) {return g(In[i]);};
  auto keys = parlay::delayed_seq<size_t>(In.size(), get_key);
  return parlay::log2_up(parlay::reduce(keys, parlay::maxm<size_t>()));
}

// Parallel radix sort implementation
template <typename T, typename F>
void parallel_radix_sort_impl(parlay::slice<T*, T*> In, 
                              parlay::slice<T*, T*> Out,
                              F get_key, 
                              size_t bits) {
  size_t n = In.size();

  // Use 8-bit radix for optimal cache performance
  constexpr size_t radix_bits = 8;
  constexpr size_t radix = 1 << radix_bits;

  size_t num_passes = (bits + radix_bits - 1) / radix_bits;

  // Allocate temporary buffer if needed
  parlay::sequence<T> temp;
  T* source = In.begin();
  T* dest = Out.begin();

  // If odd number of passes, we need a temp buffer
  if (num_passes % 2 == 1) {
    temp = parlay::sequence<T>::uninitialized(n);
    dest = temp.data();
  }

  for (size_t pass = 0; pass < num_passes; pass++) {
    size_t shift = pass * radix_bits;

    // Extract keys for this pass
    auto extract_digit = [&](const T& x) -> size_t {
      return (get_key(x) >> shift) & (radix - 1);
    };

    if (n < 1000) {
      // For small inputs, use sequential sort
      parlay::internal::seq_counting_sort<std::true_type, parlay::uninitialized_relocate_tag>
        (parlay::make_slice(source, source + n),
         parlay::make_slice(dest, dest + n),
         parlay::make_slice(source, source + n),
         extract_digit, radix);
    } else {
      // Parallel counting sort
      parlay::internal::counting_sort<std::true_type, parlay::uninitialized_relocate_tag>
        (parlay::make_slice(source, source + n),
         parlay::make_slice(dest, dest + n),
         parlay::make_slice(source, source + n),
         extract_digit, radix);
    }

    // Swap source and dest for next pass
    std::swap(source, dest);
  }

  // If the final result is not in Out, copy it
  if (source != Out.begin()) {
    parlay::parallel_for(0, n, [&](size_t i) {
      Out[i] = std::move(source[i]);
    });
  }
}

template <class T>
auto int_sort(parlay::slice<T*,T*> In, size_t bits) {
  auto Out = parlay::sequence<T>::uninitialized(In.size());

  if (In.size() == 0) return Out;

  auto f = [&] (T x) {return x;};
  if (bits == 0) bits = num_bits(In, f);

  if (In.size() < 10000) {
    // For small inputs, use sequential radix sort
    parlay::internal::seq_radix_sort<std::true_type,parlay::uninitialized_relocate_tag>
         (In, make_slice(Out), In, f, bits);
  } else {
    // Use parallel radix sort for larger inputs
    parallel_radix_sort_impl(In, make_slice(Out), f, bits);
  }

  return Out;
}

template <class E, class F>
auto int_sort(parlay::slice<std::pair<E,F>*, std::pair<E,F>*> In, size_t bits) {
  using P = std::pair<E,F>;
  auto Out = parlay::sequence<P>::uninitialized(In.size());

