        num_blocks, parlay::sequence<parlay::sequence<T>>(num_buckets)
    );

    // Parallel partitioning with block decomposition
    parlay::parallel_for(0, num_blocks, [&](size_t block_id) {
        size_t start = block_id * block_size;
        size_t end = std::min(start + block_size, n);

        // Pre-allocate estimated space for local buckets
        for (size_t b = 0; b < num_buckets; b++) {
            local_buckets[block_id][b].reserve((end - start) / num_buckets + 32);
