#include <parlay/parallel.h>
#include <parlay/sequence.h>
#include <parlay/primitives.h>
#include <algorithm>
#include <cmath>
#include <random>

template <typename T, typename Compare>
class ParallelSampleSort {
private:
    static constexpr size_t SEQUENTIAL_THRESHOLD = 2048;
    static constexpr size_t MIN_BUCKET_SIZE = 64;

    // Optimized sequential sort for small arrays
    static void sequential_sort(T* start, T* end, const Compare& comp) {
        // Use insertion sort for very small arrays
        size_t n = end - start;
        if (n <= 32) {
            for (size_t i = 1; i < n; ++i) {
                T key = std::move(start[i]);
                size_t j = i;
                while (j > 0 && comp(key, start[j-1])) {
                    start[j] = std::move(start[j-1]);
                    --j;
                }
                start[j] = std::move(key);
            }
        } else {
            std::sort(start, end, comp);
        }
    }

    // Three-way partitioning for better handling of duplicates
    static std::tuple<size_t, size_t> three_way_partition(
        T* start, T* end, const T& pivot, const Compare& comp) {

        T* lt = start;
        T* gt = end - 1;
        T* i = start;

        while (i <= gt) {
            if (comp(*i, pivot)) {
                std::swap(*i, *lt);
                ++i;
                ++lt;
            } else if (comp(pivot, *i)) {
                std::swap(*i, *gt);
                --gt;
            } else {
                ++i;
            }
        }

        return {lt - start, gt - start + 1};
    }

public:
    static void sort(parlay::sequence<T>& A, const Compare& comp) {
        size_t n = A.size();
        if (n <= SEQUENTIAL_THRESHOLD) {
            sequential_sort(A.data(), A.data() + n, comp);
            return;
        }

        // Calculate optimal number of buckets based on parallelism
        size_t num_threads = parlay::num_workers();
        size_t buckets = std::min(n / MIN_BUCKET_SIZE, 
                                  num_threads * std::max(size_t(4), 
                                  size_t(std::log2(n / SEQUENTIAL_THRESHOLD))));
        buckets = std::max(size_t(2), buckets);

        // Over-sample to get better pivots
        size_t sample_size = buckets * std::min(size_t(128), n / buckets);
        sample_size = std::min(sample_size, n / 2);

        // Generate samples using deterministic sampling for reproducibility
        parlay::sequence<T> samples(sample_size);
        size_t stride = n / sample_size;
        parlay::parallel_for(0, sample_size, [&](size_t i) {
            samples[i] = A[i * stride];
        });

        // Sort samples
        if (sample_size > SEQUENTIAL_THRESHOLD) {
            sort(samples, comp);
        } else {
            sequential_sort(samples.data(), samples.data() + sample_size, comp);
        }

        // Select pivots from sorted samples
        parlay::sequence<T> pivots(buckets - 1);
        size_t pivot_stride = sample_size / buckets;
        for (size_t i = 0; i < buckets - 1; ++i) {
            pivots[i] = samples[(i + 1) * pivot_stride];
        }

        // Count elements in each bucket using parallel binary search
        parlay::sequence<parlay::sequence<size_t>> bucket_counts(num_threads);
        for (auto& bc : bucket_counts) {
            bc = parlay::sequence<size_t>(buckets, 0);
        }

        size_t chunk_size = (n + num_threads - 1) / num_threads;
        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t start = tid * chunk_size;
            size_t end = std::min(start + chunk_size, n);

            for (size_t i = start; i < end; ++i) {
                // Binary search to find bucket
                size_t bucket = 0;
                size_t left = 0, right = buckets - 1;
                while (left < right) {
                    size_t mid = left + (right - left) / 2;
                    if (mid < pivots.size() && comp(A[i], pivots[mid])) {
                        right = mid;
                    } else {
                        left = mid + 1;
                    }
                }
                bucket = left;
                bucket_counts[tid][bucket]++;
            }
        });

        // Compute global bucket sizes and offsets
        parlay::sequence<size_t> bucket_sizes(buckets, 0);
        for (const auto& bc : bucket_counts) {
            parlay::parallel_for(0, buckets, [&](size_t i) {
                parlay::fetch_and_add(&bucket_sizes[i], bc[i]);
            });
        }

        parlay::sequence<size_t> bucket_offsets = parlay::scan(bucket_sizes).first;

        // Compute per-thread offsets within each bucket
        parlay::sequence<parlay::sequence<size_t>> thread_offsets(num_threads);
        for (size_t tid = 0; tid < num_threads; ++tid) {
            thread_offsets[tid] = parlay::sequence<size_t>(buckets);
            thread_offsets[tid][0] = bucket_offsets[0];
            for (size_t i = 1; i < buckets; ++i) {
                thread_offsets[tid][i] = thread_offsets[tid][i-1];
            }
            for (size_t prev_tid = 0; prev_tid < tid; ++prev_tid) {
                for (size_t i = 0; i < buckets; ++i) {
                    thread_offsets[tid][i] += bucket_counts[prev_tid][i];
                }
            }
        }

        // Distribute elements to buckets
        parlay::sequence<T> temp(n);
        parlay::parallel_for(0, num_threads, [&](size_t tid) {
            size_t start = tid * chunk_size;
            size_t end = std::min(start + chunk_size, n);

            parlay::sequence<size_t> local_offsets = thread_offsets[tid];

            for (size_t i = start; i < end; ++i) {
                // Find bucket using binary search
                size_t bucket = 0;
                size_t left = 0, right = buckets - 1;
                while (left < right) {
                    size_t mid = left + (right - left) / 2;
                    if (mid < pivots.size() && comp(A[i], pivots[mid])) {
                        right = mid;
                    } else {
                        left = mid + 1;
                    }
                }
                bucket = left;

                temp[local_offsets[bucket]++] = std::move(A[i]);
            }
        });

        // Copy back to original array
        parlay::parallel_for(0, n, [&](size_t i) {
            A[i] = std::move(temp[i]);
        });

        // Sort each bucket in parallel
        parlay::parallel_for(0, buckets, [&](size_t i) {
            size_t start = bucket_offsets[i];
            size_t end = (i == buckets - 1) ? n : bucket_offsets[i + 1];

            if (end - start > SEQUENTIAL_THRESHOLD) {
                parlay::sequence<T> bucket_slice(A.begin() + start, A.begin() + end);
                sort(bucket_slice, comp);
                std::copy(bucket_slice.begin(), bucket_slice.end(), A.begin() + start);
            } else if (end > start) {
                sequential_sort(A.data() + start, A.data() + end, comp);
            }
        }, 1);
    }
};

template <class T, class BinPred>
void sample_sort_inplace(parlay::sequence<T>& A, const BinPred& f) {
    if (A.size() <= 1) return;
    ParallelSampleSort<T, BinPred>::sort(A, f);
}

constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
    sample_sort_inplace(A, f);
}
