    // For small arrays, use sequential sort
    if (n < 10000) {
        std::sort(A.begin(), A.end(), f);
        return;
    }

    // Determine number of threads and samples
    size_t num_threads = std::min<size_t>(parlay::num_workers(), 
                                          std::max<size_t>(1, n / 10000));
