    parlay::parallel_for(0, num_samples, [&](size_t i) {
        samples[i] = A[std::min(i * stride, n - 1)];
    });

    // Sort samples to find splitters
    std::sort(std::execution::par_unseq, samples.begin(), samples.end(), f);

    // Select splitters (pivots)
    parlay::sequence<T> splitters(num_threads - 1);
    for (size_t i = 0; i < num_threads - 1; i++) {
        splitters[i] = samples[(i + 1) * oversampling_factor];
    }

    // Count elements per bucket
    parlay::sequence<parlay::sequence<size_t>> bucket_counts(num_threads);
    parlay::parallel_for(0, num_threads, [&](size_t tid) {
        bucket_counts[tid] = parlay::sequence<size_t>(num_threads, 0);
        size_t chunk_size = (n + num_threads - 1) / num_threads;
        size_t start = tid * chunk_size;
        size_t end = std::min(start + chunk_size, n);

        for (size_t i = start; i < end; i++) {
            size_t bucket = std::lower_bound(splitters.begin(), splitters.end(), 
                                            A[i], f) - splitters.begin();
            bucket_counts[tid][bucket]++;
        }
    });

    // Compute bucket offsets
    parlay::sequence<size_t> bucket_offsets(num_threads + 1);
    bucket_offsets[0] = 0;
    for (size_t b = 0; b < num_threads; b++) {
        size_t total = 0;
        for (size_t t = 0; t < num_threads; t++) {
            total += bucket_counts[t][b];
        }
        bucket_offsets[b + 1] = bucket_offsets[b] + total;
    }

    // Compute per-thread write positions
    parlay::sequence<parlay::sequence<size_t>> write_positions(num_threads);
    for (size_t tid = 0; tid < num_threads; tid++) {
        write_positions[tid] = parlay::sequence<size_t>(num_threads);
        for (size_t b = 0; b < num_threads; b++) {
            write_positions[tid][b] = bucket_offsets[b];
            for (size_t t = 0; t < tid; t++) {
                write_positions[tid][b] += bucket_counts[t][b];
            }
        }
    }

    // Redistribute elements to buckets
    parlay::sequence<T> temp(n);
    parlay::parallel_for(0, num_threads, [&](size_t tid) {
        size_t chunk_size = (n + num_threads - 1) / num_threads;
        size_t start = tid * chunk_size;
        size_t end = std::min(start + chunk_size, n);

        parlay::sequence<size_t> local_pos = write_positions[tid];

        for (size_t i = start; i < end; i++) {
            size_t bucket = std::lower_bound(splitters.begin(), splitters.end(), 
                                            A[i], f) - splitters.begin();
            temp[local_pos[bucket]++] = A[i];
        }
    });

    // Sort each bucket in parallel
    parlay::parallel_for(0, num_threads, [&](size_t b) {
        size_t start = bucket_offsets[b];
        size_t end = bucket_offsets[b + 1];

        if (end - start > 1) {
