constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
    // Optimized parallel quicksort with multiple improvements

    constexpr size_t INSERTION_SORT_THRESHOLD = 32;
    constexpr size_t PARALLEL_THRESHOLD = 4096;
    constexpr size_t SAMPLE_SORT_THRESHOLD = 100000;

    auto quicksort_impl = [&](auto&& self, auto slice) -> void {
        size_t n = slice.size();

        // Base case: use insertion sort for small arrays
        if (n <= INSERTION_SORT_THRESHOLD) {
            for (size_t i = 1; i < n; i++) {
                auto key = std::move(slice[i]);
                size_t j = i;
                while (j > 0 && f(key, slice[j-1])) {
                    slice[j] = std::move(slice[j-1]);
                    j--;
                }
                slice[j] = std::move(key);
            }
            return;
        }

        // For very large arrays, use sample sort
        if (n >= SAMPLE_SORT_THRESHOLD) {
            // Sample pivots
            size_t num_pivots = std::min<size_t>(std::sqrt(n), 256);
            size_t sample_size = num_pivots * 9;

            parlay::sequence<T> samples(sample_size);
            std::mt19937 gen(n);
            std::uniform_int_distribution<size_t> dist(0, n-1);

            for (size_t i = 0; i < sample_size; i++) {
                samples[i] = slice[dist(gen)];
            }

            parlay::sort_inplace(samples, f);

            parlay::sequence<T> pivots(num_pivots);
            for (size_t i = 0; i < num_pivots; i++) {
                pivots[i] = samples[i * 9 + 4];
            }

            // Partition into buckets
            auto get_bucket = [&](const T& x) -> size_t {
                size_t left = 0, right = num_pivots;
                while (left < right) {
                    size_t mid = (left + right) / 2;
                    if (f(x, pivots[mid])) right = mid;
                    else left = mid + 1;
                }
                return left;
            };

            parlay::sequence<size_t> bucket_ids(n);
            parlay::parallel_for(0, n, [&](size_t i) {
                bucket_ids[i] = get_bucket(slice[i]);
            });

            auto bucket_counts = parlay::histogram_by_key(bucket_ids);
            parlay::sequence<size_t> bucket_offsets(num_pivots + 2);
            bucket_offsets[0] = 0;
            for (size_t i = 0; i <= num_pivots; i++) {
                bucket_offsets[i+1] = bucket_offsets[i] + 
                    (i < bucket_counts.size() ? bucket_counts[i].second : 0);
            }

            parlay::sequence<T> temp(n);
            parlay::sequence<size_t> bucket_positions(num_pivots + 1, 0);

            for (size_t i = 0; i < n; i++) {
                size_t bucket = bucket_ids[i];
                size_t pos = bucket_offsets[bucket] + bucket_positions[bucket]++;
                temp[pos] = std::move(slice[i]);
            }

            parlay::parallel_for(0, n, [&](size_t i) {
                slice[i] = std::move(temp[i]);
            });

            // Recursively sort each bucket
            parlay::parallel_for(0, num_pivots + 1, [&](size_t i) {
                if (bucket_offsets[i+1] > bucket_offsets[i]) {
                    self(self, slice.cut(bucket_offsets[i], bucket_offsets[i+1]));
                }
