        // Three-way partitioning with median-of-medians pivot selection
        auto select_pivot = [&]() -> T {
            if (n < 9) return slice[n/2];

            // Sample 9 elements
            size_t step = n / 9;
            parlay::sequence<T> samples(9);
            for (size_t i = 0; i < 9; i++) {
                samples[i] = slice[i * step];
