        // Three-way partition
        auto flags_less = parlay::sequence<bool>(n);
        auto flags_equal = parlay::sequence<bool>(n);

        if (n >= PARALLEL_THRESHOLD) {
            parlay::parallel_for(0, n, [&](size_t i) {
                flags_less[i] = f(slice[i], pivot);
                flags_equal[i] = !flags_less[i] && !f(pivot, slice[i]);
            });
        } else {
            for (size_t i = 0; i < n; i++) {
                flags_less[i] = f(slice[i], pivot);
                flags_equal[i] = !flags_less[i] && !f(pivot, slice[i]);
            }
        }

        auto counts_less = parlay::pack_index(flags_less);
        auto counts_equal = parlay::pack_index(flags_equal);

        size_t n_less = counts_less.size();
        size_t n_equal = counts_equal.size();
        size_t n_greater = n - n_less - n_equal;

        if (n_less == 0 || n_greater == 0) {
            // Fallback to standard quicksort if bad pivot
            if (n >= PARALLEL_THRESHOLD) {
                parlay::internal::p_quicksort_inplace(slice, f);
            } else {
                std::sort(slice.begin(), slice.end(), f);
