        // Rearrange elements
        parlay::sequence<T> temp(n);

        if (n >= PARALLEL_THRESHOLD) {
            parlay::parallel_for(0, n_less, [&](size_t i) {
                temp[i] = std::move(slice[counts_less[i]]);
            });

            parlay::parallel_for(0, n_equal, [&](size_t i) {
                temp[n_less + i] = std::move(slice[counts_equal[i]]);
            });

            size_t greater_idx = 0;
            for (size_t i = 0; i < n; i++) {
                if (!flags_less[i] && !flags_equal[i]) {
                    temp[n_less + n_equal + greater_idx++] = std::move(slice[i]);
                }
            }

            parlay::parallel_for(0, n, [&](size_t i) {
                slice[i] = std::move(temp[i]);
            });
        } else {
            for (size_t i = 0; i < n_less; i++) {
                temp[i] = std::move(slice[counts_less[i]]);
            }
            for (size_t i = 0; i < n_equal; i++) {
                temp[n_less + i] = std::move(slice[counts_equal[i]]);
            }
            size_t greater_idx = 0;
            for (size_t i = 0; i < n; i++) {
                if (!flags_less[i] && !flags_equal[i]) {
                    temp[n_less + n_equal + greater_idx++] = std::move(slice[i]);
                }
            }
            for (size_t i = 0; i < n; i++) {
                slice[i] = std::move(temp[i]);
            }
        }

        // Recursive calls
        if (n >= PARALLEL_THRESHOLD) {
            parlay::par_do(
                [&]() { if (n_less > 1) self(self, slice.cut(0, n_less)); },
                [&]() { if (n_greater > 1) self(self, slice.cut(n_less + n_equal, n)); }
            );
        } else {
            if (n_less > 1) self(self, slice.cut(0, n_less));
            if (n_greater > 1) self(self, slice.cut(n_less + n_equal, n));
        }
    };

    quicksort_impl(quicksort_impl, parlay::make_slice(A));
}
