#include <atomic>
#include <random>
#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/slice.h"

constexpr bool INPLACE = true;

template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
    // Custom optimized parallel quicksort implementation

    constexpr size_t INSERTION_SORT_THRESHOLD = 32;
    constexpr size_t PARALLEL_THRESHOLD = 4096;
    constexpr size_t SAMPLE_SIZE = 64;

    // Insertion sort for small arrays
    auto insertion_sort = [&](T* begin, T* end) {
        for (T* i = begin + 1; i < end; ++i) {
            T key = std::move(*i);
            T* j = i - 1;
            while (j >= begin && f(key, *j)) {
                *(j + 1) = std::move(*j);
                --j;
            }
            *(j + 1) = std::move(key);
        }
    };

    // Three-way partition for handling duplicates efficiently
    auto three_way_partition = [&](T* begin, T* end, const T& pivot) -> std::pair<T*, T*> {
        T* lt = begin;
        T* gt = end;
        T* i = begin;

        while (i < gt) {
            if (f(*i, pivot)) {
                std::swap(*lt++, *i++);
            } else if (f(pivot, *i)) {
                std::swap(*i, *--gt);
            } else {
                ++i;
            }
        }
        return {lt, gt};
    };

    // Median-of-medians pivot selection for better balance
    auto select_pivot = [&](T* begin, T* end) -> T {
        size_t n = end - begin;
        if (n < SAMPLE_SIZE) {
            // Simple median of three
            T* mid = begin + n / 2;
            if (f(*mid, *begin)) std::swap(*begin, *mid);
            if (f(*(end-1), *begin)) std::swap(*begin, *(end-1));
            if (f(*(end-1), *mid)) std::swap(*mid, *(end-1));
            return *mid;
        }

        // Sample-based pivot selection
        static thread_local std::mt19937 gen(std::random_device{}());
        std::uniform_int_distribution<size_t> dist(0, n - 1);

        T samples[SAMPLE_SIZE];
        for (size_t i = 0; i < SAMPLE_SIZE; ++i) {
            samples[i] = begin[dist(gen)];
        }
        std::nth_element(samples, samples + SAMPLE_SIZE/2, samples + SAMPLE_SIZE,
                        [&](const T& a, const T& b) { return f(a, b); });
        return samples[SAMPLE_SIZE/2];
    };

    // Main recursive quicksort function
    std::function<void(T*, T*, size_t)> quicksort_rec = [&](T* begin, T* end, size_t depth) {
        while (end - begin > INSERTION_SORT_THRESHOLD) {
            // Fallback to heapsort if recursion is too deep
            if (depth == 0) {
                std::make_heap(begin, end, [&](const T& a, const T& b) { return f(b, a); });
                std::sort_heap(begin, end, [&](const T& a, const T& b) { return f(b, a); });
                return;
            }

            T pivot = select_pivot(begin, end);
            auto [lt, gt] = three_way_partition(begin, end, pivot);

            size_t n = end - begin;
            if (n > PARALLEL_THRESHOLD) {
                // Parallel recursive calls
                parlay::par_do(
                    [&]() { 
                        if (lt - begin > 1)
                            quicksort_rec(begin, lt, depth - 1); 
                    },
                    [&]() { 
                        if (end - gt > 1)
                            quicksort_rec(gt, end, depth - 1); 
                    }
                );
            } else {
                // Sequential for small subarrays
                if (lt - begin > 1)
                    quicksort_rec(begin, lt, depth - 1);
                if (end - gt > 1)
                    quicksort_rec(gt, end, depth - 1);
            }

            // Tail call optimization - continue with smaller partition
            if (lt - begin < end - gt) {
                if (lt - begin > 1)
                    quicksort_rec(begin, lt, depth - 1);
                begin = gt;
            } else {
                if (end - gt > 1)
                    quicksort_rec(gt, end, depth - 1);
                end = lt;
            }
            depth--;
        }

        // Use insertion sort for small subarrays
        if (end - begin > 1) {
            insertion_sort(begin, end);
        }
    };

    if (!A.empty()) {
        // Calculate maximum recursion depth (2 * log2(n))
        size_t max_depth = 0;
        size_t n = A.size();
        while (n > 0) {
            max_depth++;
            n >>= 1;
        }
        max_depth *= 2;

        quicksort_rec(A.data(), A.data() + A.size(), max_depth);
    }
}
