constexpr bool INPLACE = true;

template <typename T, typename Compare>
class OptimizedParallelQuickSort {
private:
    static constexpr size_t INSERTION_SORT_THRESHOLD = 32;
    static constexpr size_t PARALLEL_THRESHOLD = 4096;
    static constexpr int MAX_DEPTH_FACTOR = 2;

    // Optimized insertion sort for small arrays
    static void insertion_sort(T* arr, size_t n, const Compare& comp) {
        for (size_t i = 1; i < n; ++i) {
            T key = std::move(arr[i]);
            size_t j = i;
            while (j > 0 && comp(key, arr[j-1])) {
                arr[j] = std::move(arr[j-1]);
                --j;
            }
            if (j != i) {
                arr[j] = std::move(key);
            }
        }
    }

    // Median-of-three pivot selection with ninther for large arrays
    static T* select_pivot(T* first, T* last, const Compare& comp) {
        size_t n = last - first;
        T* mid = first + n/2;

        if (n > 128) {
            // Use ninther (median of three medians) for large arrays
            size_t step = n/8;
            T* m1 = median_of_three(first, first + step, first + 2*step, comp);
            T* m2 = median_of_three(mid - step, mid, mid + step, comp);
            T* m3 = median_of_three(last - 2*step - 1, last - step - 1, last - 1, comp);
            return median_of_three(m1, m2, m3, comp);
        } else {
            return median_of_three(first, mid, last - 1, comp);
        }
    }

    static T* median_of_three(T* a, T* b, T* c, const Compare& comp) {
        if (comp(*a, *b)) {
            if (comp(*b, *c)) return b;
            else if (comp(*a, *c)) return c;
            else return a;
        } else {
            if (comp(*a, *c)) return a;
            else if (comp(*b, *c)) return c;
            else return b;
        }
    }

    // Three-way partitioning for better handling of duplicates
    static std::pair<T*, T*> three_way_partition(T* first, T* last, const Compare& comp) {
        T* pivot_ptr = select_pivot(first, last, comp);
        T pivot = std::move(*pivot_ptr);
        *pivot_ptr = std::move(*first);

        T* lt = first;
        T* gt = last;
        T* i = first + 1;

        while (i < gt) {
            if (comp(*i, pivot)) {
                std::swap(*lt, *i);
                ++lt;
                ++i;
            } else if (comp(pivot, *i)) {
                --gt;
                std::swap(*i, *gt);
            } else {
                ++i;
            }
        }

        return {lt, gt};
    }

    // Optimized two-way partition with better cache locality
    static T* partition_bidirectional(T* first, T* last, const Compare& comp) {
        T* pivot_ptr = select_pivot(first, last, comp);
        std::swap(*first, *pivot_ptr);
        T& pivot = *first;

        T* left = first + 1;
        T* right = last - 1;

        while (true) {
            while (left <= right && comp(*left, pivot)) ++left;
            while (left <= right && !comp(*right, pivot)) --right;
            if (left > right) break;
            std::swap(*left, *right);
            ++left;
            --right;
        }

        std::swap(*first, *right);
        return right;
    }

    static void parallel_quicksort_impl(T* first, T* last, const Compare& comp, int depth) {
        while (last - first > INSERTION_SORT_THRESHOLD) {
            size_t n = last - first;

            // Switch to sequential for small arrays or deep recursion
            if (n < PARALLEL_THRESHOLD || depth <= 0) {
                sequential_quicksort(first, last, comp);
                return;
            }

            // Use three-way partitioning for potentially many duplicates
            if (n > 100000) {
                auto [lt, gt] = three_way_partition(first, last, comp);

                if (lt - first < last - gt) {
                    parlay::par_do(
                        [&]() { parallel_quicksort_impl(first, lt, comp, depth - 1); },
                        [&]() { parallel_quicksort_impl(gt, last, comp, depth - 1); }
                    );
                } else {
                    parlay::par_do(
                        [&]() { parallel_quicksort_impl(gt, last, comp, depth - 1); },
                        [&]() { parallel_quicksort_impl(first, lt, comp, depth - 1); }
                    );
                }
                return;
            } else {
                // Standard two-way partition for moderate sizes
                T* mid = partition_bidirectional(first, last, comp);

                // Parallel recursion on larger partition first
                if (mid - first < last - mid - 1) {
                    parlay::par_do(
                        [&]() { parallel_quicksort_impl(first, mid, comp, depth - 1); },
                        [&]() { parallel_quicksort_impl(mid + 1, last, comp, depth - 1); }
                    );
                } else {
                    parlay::par_do(
                        [&]() { parallel_quicksort_impl(mid + 1, last, comp, depth - 1); },
                        [&]() { parallel_quicksort_impl(first, mid, comp, depth - 1); }
                    );
                }
                return;
            }
        }

        if (first < last) {
            insertion_sort(first, last - first, comp);
        }
    }

    static void sequential_quicksort(T* first, T* last, const Compare& comp) {
        while (last - first > INSERTION_SORT_THRESHOLD) {
            T* mid = partition_bidirectional(first, last, comp);

            // Tail recursion optimization
            if (mid - first < last - mid - 1) {
                sequential_quicksort(first, mid, comp);
                first = mid + 1;
            } else {
                sequential_quicksort(mid + 1, last, comp);
                last = mid;
            }
        }

        if (first < last) {
            insertion_sort(first, last - first, comp);
        }
    }

public:
    static void sort(T* first, T* last, const Compare& comp) {
        size_t n = last - first;
        if (n <= 1) return;

        // Calculate maximum recursion depth
        int max_depth = 0;
        size_t temp = n;
        while (temp > 1) {
            temp >>= 1;
            max_depth++;
        }
        max_depth *= MAX_DEPTH_FACTOR;

        parallel_quicksort_impl(first, last, comp, max_depth);
    }
};

template <class T, class BinPred>
void compSort(parlay::sequence<T>& A, const BinPred& f) {
    if (A.size() <= 1) return;

    OptimizedParallelQuickSort<T, BinPred>::sort(A.data(), A.data() + A.size(), f);
}
