#include "parlay/parallel.h"
#include "parlay/sequence.h"
#include "parlay/slice.h"
#include <algorithm>
#include <cstring>

constexpr bool INPLACE = true;

namespace {
    constexpr size_t INSERTION_SORT_THRESHOLD = 32;
    constexpr size_t PARALLEL_THRESHOLD = 8192;

    template<typename T, typename Compare>
    void insertion_sort(T* arr, size_t n, const Compare& comp) {
        for (size_t i = 1; i < n; ++i) {
            T key = std::move(arr[i]);
            size_t j = i;
            while (j > 0 && comp(key, arr[j-1])) {
                arr[j] = std::move(arr[j-1]);
                --j;
            }
            arr[j] = std::move(key);
        }
    }

    template<typename T, typename Compare>
    size_t binary_search_upper(T* arr, size_t n, const T& val, const Compare& comp) {
        size_t left = 0, right = n;
        while (left < right) {
            size_t mid = left + (right - left) / 2;
            if (comp(val, arr[mid])) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }

    template<typename T, typename Compare>
    void parallel_merge(T* src, T* dest, size_t left_size, size_t right_size, 
                       const Compare& comp) {
        size_t total = left_size + right_size;

        if (total <= PARALLEL_THRESHOLD) {
            // Sequential merge for small inputs
            T* left = src;
            T* right = src + left_size;
            size_t i = 0, j = 0, k = 0;

            while (i < left_size && j < right_size) {
                if (!comp(right[j], left[i])) {
                    dest[k++] = std::move(left[i++]);
                } else {
                    dest[k++] = std::move(right[j++]);
                }
            }

            if (i < left_size) {
                std::move(left + i, left + left_size, dest + k);
            } else if (j < right_size) {
                std::move(right + j, right + right_size, dest + k);
            }
        } else {
            // Parallel merge
            size_t mid_left = left_size / 2;
            T& pivot = src[mid_left];
            size_t mid_right = binary_search_upper(src + left_size, right_size, pivot, comp);
            size_t mid_dest = mid_left + mid_right;

            dest[mid_dest] = std::move(pivot);

            parlay::par_do(
                [&]() {
                    if (mid_left > 0) {
                        parallel_merge(src, dest, mid_left, mid_right, comp);
                    }
                },
                [&]() {
                    if (left_size - mid_left - 1 + right_size - mid_right > 0) {
                        parallel_merge(src + mid_left + 1, dest + mid_dest + 1,
                                     left_size - mid_left - 1, 
                                     right_size - mid_right, comp);
                    }
                }
            );
        }
    }

    template<typename T, typename Compare>
    void merge_sort_recursive(T* arr, T* temp, size_t n, const Compare& comp, bool arr_is_src) {
        if (n <= INSERTION_SORT_THRESHOLD) {
            if (arr_is_src) {
                insertion_sort(arr, n, comp);
            } else {
                std::move(arr, arr + n, temp);
                insertion_sort(temp, n, comp);
            }
            return;
        }

        size_t mid = n / 2;

        if (n > PARALLEL_THRESHOLD) {
            parlay::par_do(
                [&]() { merge_sort_recursive(arr, temp, mid, comp, !arr_is_src); },
                [&]() { merge_sort_recursive(arr + mid, temp + mid, n - mid, comp, !arr_is_src); }
            );
        } else {
            merge_sort_recursive(arr, temp, mid, comp, !arr_is_src);
            merge_sort_recursive(arr + mid, temp + mid, n - mid, comp, !arr_is_src);
        }

        if (arr_is_src) {
            parallel_merge(temp, arr, mid, n - mid, comp);
        } else {
            parallel_merge(arr, temp, mid, n - mid, comp);
        }
    }
}

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
    size_t n = A.size();
    if (n <= 1) return;

    if (n <= INSERTION_SORT_THRESHOLD) {
        insertion_sort(A.data(), n, f);
        return;
    }

    parlay::sequence<T> temp(n);
    merge_sort_recursive(A.data(), temp.data(), n, f, true);
}
