  auto merge_sort_rec = [&](auto&& self, T* src, T* dst, size_t left, size_t right) -> void {
    size_t len = right - left;

    // Base case: use insertion sort for small subarrays
    if (len <= INSERTION_THRESHOLD) {
      // Copy to destination if needed
      if (src != dst) {
        std::memcpy(dst + left, src + left, len * sizeof(T));
      }
      // Insertion sort in place
      for (size_t i = left + 1; i < right; i++) {
        T key = std::move(dst[i]);
        size_t j = i;
        while (j > left && f(key, dst[j-1])) {
          dst[j] = std::move(dst[j-1]);
          j--;
        }
        dst[j] = std::move(key);
      }
      return;
    }

    size_t mid = left + (len >> 1);

    // Parallel recursion for large enough subarrays
    constexpr size_t PARALLEL_THRESHOLD = 8192;
    if (len >= PARALLEL_THRESHOLD) {
      parlay::par_do(
        [&] { self(self, dst, src, left, mid); },
        [&] { self(self, dst, src, mid, right); }
      );
    } else {
      self(self, dst, src, left, mid);
      self(self, dst, src, mid, right);
    }

