    size_t i = left, j = mid, k = left;

    // Check if already sorted (optimization for nearly sorted data)
    if (!f(src[mid], src[mid-1])) {
      std::memcpy(dst + left, src + left, len * sizeof(T));
      return;
    }

    // Galloping mode for skewed merges
    auto gallop_merge = [&]() {
      while (i < mid && j < right) {
        if (f(src[j], src[i])) {
          // Gallop in right subarray
          size_t k_start = j;
          size_t step = 1;
          while (j + step < right && f(src[j + step], src[i])) {
            j += step;
            step <<= 1;
          }
          // Binary search for exact position
          size_t lo = j, hi = std::min(j + step, right);
          while (lo < hi) {
            size_t m = lo + ((hi - lo) >> 1);
            if (f(src[m], src[i])) lo = m + 1;
            else hi = m;
          }
          // Copy run
          std::memcpy(dst + k, src + k_start, (lo - k_start) * sizeof(T));
          k += lo - k_start;
          j = lo;
          if (j < right) dst[k++] = std::move(src[i++]);
        } else {
          // Gallop in left subarray
          size_t k_start = i;
          size_t step = 1;
          while (i + step < mid && !f(src[j], src[i + step])) {
            i += step;
            step <<= 1;
          }
          // Binary search for exact position
          size_t lo = i, hi = std::min(i + step, mid);
          while (lo < hi) {
            size_t m = lo + ((hi - lo) >> 1);
            if (!f(src[j], src[m])) lo = m + 1;
            else hi = m;
          }
          // Copy run
          std::memcpy(dst + k, src + k_start, (lo - k_start) * sizeof(T));
          k += lo - k_start;
          i = lo;
          if (i < mid) dst[k++] = std::move(src[j++]);
        }
      }
    };

    // Standard merge with run detection
    constexpr size_t MIN_GALLOP = 7;
    size_t count_left = 0, count_right = 0;

    while (i < mid && j < right) {
      if (f(src[j], src[i])) {
        dst[k++] = std::move(src[j++]);
        count_right++;
        count_left = 0;
        if (count_right >= MIN_GALLOP) {
