    tmp[i] = A[i];
  });

  // Determine number of merge passes needed
  size_t num_passes = 0;
  size_t temp = n;
  while (temp > INSERTION_THRESHOLD) {
    temp = (temp + 1) >> 1;
    num_passes++;
  }

  // Perform merge sort
  if (num_passes & 1) {
    // Odd number of passes: final result in A
    merge_sort_rec(merge_sort_rec, tmp.data(), A.data(), 0, n);
  } else {
    // Even number of passes: need to copy back
    merge_sort_rec(merge_sort_rec, A.data(), tmp.data(), 0, n);
    parlay::parallel_for(0, n, [&](size_t i) {
      A[i] = std::move(tmp[i]);
    });
  }
