            size_t total = left_size + right_size;
            size_t mid = total / 2;

            T* left_ptr = src;
            T* right_ptr = src + left_size;

            size_t left_split, right_split;
            if (left_size > right_size) {
                left_split = left_size / 2;
                right_split = std::lower_bound(right_ptr, right_ptr + right_size, 
                                              left_ptr[left_split], comp) - right_ptr;
            } else {
                right_split = right_size / 2;
                left_split = std::lower_bound(left_ptr, left_ptr + left_size,
                                             right_ptr[right_split], 
                                             [&](const T& a, const T& b) { return !comp(b, a); }) - left_ptr;
            }

            size_t split_pos = left_split + right_split;

            parlay::par_do(
                [&]() { parallel_merge(src, dst, left_split, right_split, comp); },
                [&]() { parallel_merge(src + left_split + right_split, 
                                     dst + split_pos,
                                     left_size - left_split, 
                                     right_size - right_split, comp); }
            );
        }
    }

    template<typename T, typename Comp>
    void merge_sort_recursive(T* data, T* buffer, size_t n, const Comp& comp, bool data_is_src) {
        if (n <= INSERTION_SORT_THRESHOLD) {
            insertion_sort(data, data + n, comp);
            if (!data_is_src) {
                std::move(data, data + n, buffer);
            }
            return;
        }

        size_t mid = n / 2;

        if (n >= PARALLEL_THRESHOLD) {
            parlay::par_do(
                [&]() { merge_sort_recursive(data, buffer, mid, comp, !data_is_src); },
                [&]() { merge_sort_recursive(data + mid, buffer + mid, n - mid, comp, !data_is_src); }
            );
        } else {
            merge_sort_recursive(data, buffer, mid, comp, !data_is_src);
            merge_sort_recursive(data + mid, buffer + mid, n - mid, comp, !data_is_src);
        }

        if (data_is_src) {
            parallel_merge(buffer, data, mid, n - mid, comp);
        } else {
            parallel_merge(data, buffer, mid, n - mid, comp);
        }
    }
}

template <class T, class BinPred>
void compSort(parlay::sequence<T> &A, const BinPred& f) {
    size_t n = A.size();
    if (n <= 1) return;

    if (n <= INSERTION_SORT_THRESHOLD) {
        insertion_sort(A.begin(), A.end(), f);
        return;
    }

    parlay::sequence<T> buffer(n);
    merge_sort_recursive(A.data(), buffer.data(), n, f, true);
}
