#include <atomic>
#include <tbb/concurrent_hash_map.h>
#include "parlay/parallel.h"
#include "parlay/primitives.h"
#include "parlay/io.h"
#include "parlay/internal/get_time.h"
#include "wc.h"

using namespace std;

// Custom hash function for character sequences
struct CharSeqHash {
    size_t operator()(const charseq& s) const {
        size_t hash = 0;
        size_t prime = 31;
        for (size_t i = 0; i < std::min(s.size(), size_t(16)); i++) {
            hash = hash * prime + s[i];
        }
        hash ^= s.size();
        return hash;
    }
};

struct CharSeqEqual {
    bool operator()(const charseq& a, const charseq& b) const {
        return a.size() == b.size() && 
               std::equal(a.begin(), a.end(), b.begin());
    }
};

parlay::sequence<result_type> wordCounts(charseq const &s, bool verbose=false) {
    parlay::internal::timer t("word counts", verbose);
    if (verbose) cout << "number of characters = " << s.size() << endl;

    size_t n = s.size();
    if (n == 0) return {};

    // Process characters and find word boundaries in parallel
    // Use atomic flags for word boundaries to avoid race conditions
    auto processed = parlay::sequence<char>(n + 1);
    auto is_word_start = parlay::sequence<bool>(n + 1, false);

    // Process in cache-friendly blocks
    size_t block_size = 65536; // 64KB blocks for better cache utilization
    size_t num_blocks = (n + block_size - 1) / block_size;

    parlay::parallel_for(0, num_blocks, [&](size_t b) {
        size_t start = b * block_size;
        size_t end = std::min(start + block_size, n);

        bool prev_was_separator = (start == 0) || (processed[start-1] == 0);

        for (size_t i = start; i < end; i++) {
            char c = s[i];
            char pc;
            if (c >= 65 && c < 91) pc = c + 32;      // upper to lower
            else if (c >= 97 && c < 123) pc = c;     // already lower
            else pc = 0;                             // separator

            processed[i] = pc;

            // Mark word starts
            if (pc != 0 && prev_was_separator) {
                is_word_start[i] = true;
            }
            prev_was_separator = (pc == 0);
        }
    });
    processed[n] = 0; // sentinel
    t.next("process chars");

    // Collect word start positions in parallel
    auto word_starts = parlay::pack_index(is_word_start);
    size_t num_words = word_starts.size();
    t.next("find word starts");

    if (verbose) cout << "number of words = " << num_words << endl;

    // Use TBB concurrent hash map for better parallel performance
    using HashMap = tbb::concurrent_hash_map<charseq, std::atomic<size_t>*, CharSeqHash, CharSeqEqual>;
    HashMap word_map(num_words / 10); // Initial size estimate

    // Process words in parallel batches to reduce contention
    size_t batch_size = 1024;
    size_t num_batches = (num_words + batch_size - 1) / batch_size;

    parlay::parallel_for(0, num_batches, [&](size_t batch) {
        size_t start_idx = batch * batch_size;
        size_t end_idx = std::min(start_idx + batch_size, num_words);

        for (size_t idx = start_idx; idx < end_idx; idx++) {
            size_t i = word_starts[idx];
            size_t j = i;
