                HashMap::accessor acc;
                if (word_map.insert(acc, word)) {
                    // New word, initialize counter
                    acc->second = new std::atomic<size_t>(1);
                } else {
                    // Existing word, increment counter
                    acc->second->fetch_add(1, std::memory_order_relaxed);
                }
            }
        }
    }, 1); // Granularity of 1 for better load balancing
    t.next("build histogram");

    // Convert to output format
    auto result = parlay::sequence<result_type>::uninitialized(word_map.size());

    auto it = word_map.begin();
    parlay::parallel_for(0, word_map.size(), [&](size_t i) {
