    auto names = parlay::sequence<indexT>::uninitialized(l);

    // mark start of each segment with equal keys
    parlay::parallel_for (1, l, [&] (size_t i) {
	names[i] = (Cs[i].first != Cs[i-1].first) ? i : 0;});
